59	/// A querier that allows sending queries to a [`Queryable`](crate::query::Queryable).
60	///
61	/// The querier is a preconfigured object that can be used to send multiple
62	/// queries to a given key expression. It is declared using
63	/// [`Session::declare_querier`](crate::Session::declare_querier).
64	///
65	/// # Examples
66	/// ```
67	/// # #[tokio::main]
68	/// # async fn main() {
69	///
70	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
71	/// let querier = session.declare_querier("key/expression").await.unwrap();
72	/// let replies = querier.get().await.unwrap();
73	/// # }
74	/// ```
75	#[derive(Debug)]
76	pub struct Querier<'a> {
77	    pub(crate) session: WeakSession,
78	    pub(crate) id: Id,
79	    pub(crate) key_expr: KeyExpr<'a>,
