100	impl<'a> Querier<'a> {
101	    /// Returns the [`EntityGlobalId`] of this Querier.
102	    ///
103	    /// # Examples
104	    /// ```
105	    /// # #[tokio::main]
106	    /// # async fn main() {
107	    ///
108	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
109	    /// let querier = session.declare_querier("key/expression")
110	    ///     .await
111	    ///     .unwrap();
112	    /// let querier_id = querier.id();
113	    /// # }
114	    /// ```
115	    #[zenoh_macros::unstable]
116	    pub fn id(&self) -> EntityGlobalId {
117	        EntityGlobalIdProto {
118	            zid: self.session.zid().into(),
119	            eid: self.id,
120	        }
121	        .into()
122	    }
123	
124	    /// Returns the [`KeyExpr`] this querier sends queries on.
125	    #[inline]
126	    pub fn key_expr(&self) -> &KeyExpr<'a> {
127	        &self.key_expr
128	    }
129	
130	    /// Get the [`CongestionControl`] applied when routing the data.
131	    #[inline]
132	    pub fn congestion_control(&self) -> CongestionControl {
133	        self.qos.congestion_control()
134	    }
135	
136	    /// Get the [`Priority`] of the querier requests.
137	    #[inline]
138	    pub fn priority(&self) -> Priority {
139	        self.qos.priority()
140	    }
141	
142	    /// See details in the [`ReplyKeyExpr`](crate::query::ReplyKeyExpr) documentation.
143	    ///
144	    /// Queries may or may not accept replies on key expressions that do not intersect with their own key expression.
145	    /// This getter allows you to check whether this querier accepts such disjoint replies.
146	    /// Currently, this information is passed in the [`Selector`](crate::api::selector::Selector) parameters as the `_anyke` parameter.
147	    #[inline]
148	    pub fn accept_replies(&self) -> ReplyKeyExpr {
149	        self.accept_replies
150	    }
151	
152	    /// Send a query. Returns a builder to customize the query. The builder
153	    /// resolves to a [`handler`](crate::handlers) generating a series of
154	    /// [`Reply`](crate::api::query::Reply) values for each response received.
155	    ///
156	    /// # Examples
157	    /// ```
158	    /// # #[tokio::main]
159	    /// # async fn main() {
160	    ///
161	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
162	    /// let querier = session.declare_querier("key/expression").await.unwrap();
163	    /// let replies = querier.get();
164	    /// # }
165	    /// ```
166	    #[inline]
167	    pub fn get(&self) -> QuerierGetBuilder<'_, '_, DefaultHandler> {
168	        QuerierGetBuilder {
169	            querier: self,
170	            #[cfg(feature = "unstable")]
171	            source_info: None,
172	            value: None,
173	            attachment: None,
174	            parameters: Parameters::empty(),
175	            handler: DefaultHandler::default(),
176	            #[cfg(feature = "unstable")]
177	            cancellation_token: None,
178	        }
179	    }
