181	    /// Undeclare the [`Querier`], informing the network that it needn't optimize queries for its key expression anymore.
182	    ///
183	    /// # Examples
184	    /// ```
185	    /// # #[tokio::main]
186	    /// # async fn main() {
187	    ///
188	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
189	    /// let querier = session.declare_querier("key/expression").await.unwrap();
190	    /// querier.undeclare().await.unwrap();
191	    /// # }
192	    /// ```
193	    pub fn undeclare(self) -> QuerierUndeclaration<'a> {
194	        UndeclarableSealed::undeclare_inner(self, ())
195	    }
196	
197	    fn undeclare_impl(&mut self) -> ZResult<()> {
198	        // set the flag first to avoid double panic if this function panics
199	        self.undeclare_on_drop = false;
200	        let ids: Vec<Id> = zlock!(self.matching_listeners).drain().collect();
201	        for id in ids {
202	            self.session.undeclare_matches_listener_inner(id)?
203	        }
204	        self.session.undeclare_querier_inner(self.id)
205	    }
