207	    /// Return the [`MatchingStatus`] of the querier.
208	    ///
209	    /// [`MatchingStatus::matching`] will return true if there are Queryables
210	    /// matching the Querier's key expression and target, and false otherwise.
211	    ///
212	    /// # Examples
213	    /// ```
214	    /// # #[tokio::main]
215	    /// # async fn main() {
216	    ///
217	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
218	    /// let querier = session.declare_querier("key/expression").await.unwrap();
219	    /// let matching_queriers: bool = querier
220	    ///     .matching_status()
221	    ///     .await
222	    ///     .unwrap()
223	    ///     .matching();
224	    /// # }
225	    /// ```
226	    pub fn matching_status(&self) -> impl Resolve<ZResult<MatchingStatus>> + '_ {
227	        zenoh_core::ResolveFuture::new(async move {
228	            self.session.matching_status(
229	                self.key_expr(),
230	                self.destination,
231	                MatchingStatusType::Queryables(self.target == QueryTarget::AllComplete),
232	            )
233	        })
234	    }
