236	    /// Return a [`MatchingListener`](crate::api::matching::MatchingListener) for this Querier.
237	    ///
238	    /// The [`MatchingListener`](crate::api::matching::MatchingListener) will send a notification each time the [`MatchingStatus`](crate::api::matching::MatchingStatus) of
239	    /// the Querier changes.
240	    ///
241	    /// # Examples
242	    /// ```no_run
243	    /// # #[tokio::main]
244	    /// # async fn main() {
245	    ///
246	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
247	    /// let querier = session.declare_querier("key/expression").await.unwrap();
248	    /// let matching_listener = querier.matching_listener().await.unwrap();
249	    /// while let Ok(matching_status) = matching_listener.recv_async().await {
250	    ///     if matching_status.matching() {
251	    ///         println!("Querier has matching queryables.");
252	    ///     } else {
253	    ///         println!("Querier has NO MORE matching queryables.");
254	    ///     }
255	    /// }
256	    /// # }
257	    /// ```
258	    pub fn matching_listener(&self) -> MatchingListenerBuilder<'_, DefaultHandler> {
259	        MatchingListenerBuilder {
260	            session: &self.session,
261	            key_expr: &self.key_expr,
262	            destination: self.destination,
263	            matching_listeners: &self.matching_listeners,
264	            matching_status_type: MatchingStatusType::Queryables(
265	                self.target == QueryTarget::AllComplete,
266	            ),
267	            handler: DefaultHandler::default(),
268	            parent_callback_sync_group_notifier: self.callback_sync_group.notifier(),
269	        }
270	    }
271	
272	    #[zenoh_macros::internal]
273	    pub fn session(&self) -> &WeakSession {
274	        &self.session
275	    }
276	}
