278	impl<'a> UndeclarableSealed<()> for Querier<'a> {
279	    type Undeclaration = QuerierUndeclaration<'a>;
280	
281	    fn undeclare_inner(self, _: ()) -> Self::Undeclaration {
282	        QuerierUndeclaration {
283	            querier: self,
284	            wait_callbacks: false,
285	        }
286	    }
287	}
288	
289	/// A [`Resolvable`] returned when undeclaring a querier.
290	///
291	/// # Examples
292	/// ```
293	/// # #[tokio::main]
294	/// # async fn main() {
295	///
296	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
297	/// let querier = session.declare_querier("key/expression").await.unwrap();
298	/// querier.undeclare().await.unwrap();
299	/// # }
300	/// ```
301	#[must_use = "Resolvables do nothing unless you resolve them using `.await` or `zenoh::Wait::wait`"]
302	pub struct QuerierUndeclaration<'a> {
303	    querier: Querier<'a>,
304	    wait_callbacks: bool,
305	}
306	
307	impl fmt::Debug for QuerierUndeclaration<'_> {
308	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
309	        f.debug_struct("QuerierUndeclaration")
310	            .field("querier", &self.querier)
311	            .field("wait_callbacks", &self.wait_callbacks)
312	            .finish()
313	    }
314	}
315	
316	impl<'a> QuerierUndeclaration<'a> {
317	    #[zenoh_macros::internal_or_unstable]
318	    /// Block in undeclare operation until all currently running instances of reply and matching listeners' callbacks (if any) return.
319	    pub fn wait_callbacks(mut self) -> Self {
320	        self.wait_callbacks = true;
321	        self
322	    }
323	}
324	
325	impl Resolvable for QuerierUndeclaration<'_> {
326	    type To = ZResult<()>;
327	}
328	
329	impl Wait for QuerierUndeclaration<'_> {
330	    fn wait(mut self) -> <Self as Resolvable>::To {
331	        self.querier.undeclare_impl()?;
332	        if self.wait_callbacks {
333	            self.querier.callback_sync_group.wait();
334	        }
335	        Ok(())
336	    }
337	}
338	
339	impl IntoFuture for QuerierUndeclaration<'_> {
340	    type Output = <Self as Resolvable>::To;
341	    type IntoFuture = Ready<<Self as Resolvable>::To>;
342	
343	    fn into_future(self) -> Self::IntoFuture {
344	        std::future::ready(self.wait())
345	    }
346	}
347	
348	impl Drop for Querier<'_> {
349	    fn drop(&mut self) {
350	        if self.undeclare_on_drop {
351	            if let Err(error) = self.undeclare_impl() {
352	                error!(error);
353	            }
354	        }
355	    }
356	}
