481	    fn wait(self) -> <Self as Resolvable>::To {
482	        let (callback, receiver) = self.handler.into_handler();
483	        #[allow(unused_mut)]
484	        // mut is only needed when building with "unstable" feature, which might add extra internal parameters on top of the user-provided ones
485	        let mut parameters = self.parameters.clone();
486	        if self.querier.accept_replies() == ReplyKeyExpr::Any {
487	            parameters.insert(REPLY_KEY_EXPR_ANY_SEL_PARAM, "");
488	        }
489	        self.querier.session.query(
490	            &self.querier.key_expr,
491	            &parameters,
492	            self.querier.target,
493	            self.querier.consolidation,
494	            self.querier.qos,
495	            self.querier.destination,
496	            self.querier.timeout,
497	            self.value,
498	            self.attachment,
499	            #[cfg(feature = "unstable")]
500	            self.source_info,
501	            callback,
502	            #[cfg(feature = "unstable")]
503	            self.cancellation_token,
504	            Some(self.querier.id),
505	            self.querier.callback_sync_group.notifier(),
