43	/// A builder for configuring a [`get`](crate::Session::get)
44	/// operation from a [`Session`](crate::Session).
45	/// The builder resolves to a [`handler`](crate::handlers) generating a series of
46	/// [`Reply`](crate::api::query::Reply) for each response received.
47	///
48	/// # Examples
49	/// ```
50	/// # #[tokio::main]
51	/// # async fn main() {
52	/// use zenoh::{query::{ConsolidationMode, QueryTarget}};
53	///
54	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
55	/// let replies = session
56	///     .get("key/expression?value>1")
57	///     .target(QueryTarget::All)
58	///     .consolidation(ConsolidationMode::None)
59	///     .await
60	///     .unwrap();
61	/// while let Ok(reply) = replies.recv_async().await {
62	///     println!("Received {:?}", reply.result())
63	/// }
64	/// # }
65	/// ```
66	#[must_use = "Resolvables do nothing unless you resolve them using `.await` or `zenoh::Wait::wait`"]
67	#[derive(Debug)]
68	pub struct SessionGetBuilder<'a, 'b, Handler> {
69	    pub(crate) session: &'a Session,
70	    pub(crate) selector: ZResult<Selector<'b>>,
71	    pub(crate) target: QueryTarget,
72	    pub(crate) consolidation: QueryConsolidation,
73	    pub(crate) qos: QoSBuilder,
74	    pub(crate) destination: Locality,
75	    pub(crate) timeout: Duration,
76	    pub(crate) handler: Handler,
77	    pub(crate) value: Option<(ZBytes, Encoding)>,
78	    pub(crate) attachment: Option<ZBytes>,
79	    #[cfg(feature = "unstable")]
80	    pub(crate) source_info: Option<SourceInfo>,
81	    #[cfg(feature = "unstable")]
82	    pub(crate) cancellation_token: Option<crate::api::cancellation::CancellationToken>,
83	}
