88	    /// Sets an optional [`SourceInfo`](crate::sample::SourceInfo) to be sent along with the request/query.
89	    fn source_info<T: Into<Option<SourceInfo>>>(self, source_info: T) -> Self {
90	        Self {
91	            source_info: source_info.into(),
92	            ..self
93	        }
94	    }
