96	    /// Sets an optional attachment to be sent along with the request/query.
97	    /// The method accepts both `T` where `T: Into<ZBytes>` and `Option<T>` where `T: Into<ZBytes>` (see [`OptionZBytes`](crate::bytes::OptionZBytes)).
98	    fn attachment<T: Into<OptionZBytes>>(self, attachment: T) -> Self {
99	        let attachment: OptionZBytes = attachment.into();
100	        Self {
101	            attachment: attachment.into(),
102	            ..self
103	        }
104	    }
