107	#[zenoh_macros::internal_trait]
108	impl<Handler> QoSBuilderTrait for SessionGetBuilder<'_, '_, Handler> {
109	    /// Changes the [`CongestionControl`](crate::qos::CongestionControl) to apply when routing the request.
110	    fn congestion_control(self, congestion_control: CongestionControl) -> Self {
111	        let qos = self.qos.congestion_control(congestion_control);
112	        Self { qos, ..self }
113	    }
114	
115	    /// Changes the [`Priority`](crate::qos::Priority) of the request.
116	    fn priority(self, priority: Priority) -> Self {
117	        let qos = self.qos.priority(priority);
118	        Self { qos, ..self }
119	    }
