146	impl<Handler> CancellationTokenBuilderTrait for SessionGetBuilder<'_, '_, Handler> {
147	    /// Provide a cancellation token that can be used later to interrupt GET operation.
148	    ///
149	    /// # Examples
150	    /// ```
151	    /// # #[tokio::main]
152	    /// # async fn main() {
153	    ///
154	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
155	    /// let ct = zenoh::cancellation::CancellationToken::default();
156	    /// let query = session
157	    ///     .get("key/expression")
158	    ///     .callback(|reply| {println!("Received {:?}", reply.result());})
159	    ///     .cancellation_token(ct.clone())
160	    ///     .await
161	    ///     .unwrap();
162	    ///
163	    /// tokio::task::spawn(async move {
164	    ///     tokio::time::sleep(std::time::Duration::from_secs(10)).await;
165	    ///     ct.cancel().await.unwrap();
166	    /// });
167	    /// # }
