169	    #[zenoh_macros::unstable_doc]
170	    fn cancellation_token(
171	        self,
172	        cancellation_token: crate::api::cancellation::CancellationToken,
173	    ) -> Self {
174	        Self {
175	            cancellation_token: Some(cancellation_token),
176	            ..self
177	        }
178	    }
