181	impl<'a, 'b> SessionGetBuilder<'a, 'b, DefaultHandler> {
182	    /// Receive the replies for this query with a callback.
183	    ///
184	    /// # Examples
185	    /// ```
186	    /// # #[tokio::main]
187	    /// # async fn main() {
188	    ///
189	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
190	    /// let queryable = session
191	    ///     .get("key/expression")
192	    ///     .callback(|reply| {println!("Received {:?}", reply.result());})
193	    ///     .await
194	    ///     .unwrap();
195	    /// # }
196	    /// ```
197	    #[inline]
198	    pub fn callback<F>(self, callback: F) -> SessionGetBuilder<'a, 'b, Callback<Reply>>
199	    where
200	        F: Fn(Reply) + Send + Sync + 'static,
201	    {
202	        self.with(Callback::from(callback))
203	    }
204	
205	    /// Receive the replies for this query with a mutable callback.
206	    ///
207	    /// Using this guarantees that your callback will never be called concurrently.
208	    /// If your callback is also accepted by the [`callback`](crate::session::SessionGetBuilder::callback) method, we suggest you use it instead of `callback_mut`.
209	    ///
210	    /// # Examples
211	    /// ```
212	    /// # #[tokio::main]
213	    /// # async fn main() {
214	    ///
215	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
216	    /// let mut n = 0;
217	    /// let queryable = session
218	    ///     .get("key/expression")
219	    ///     .callback_mut(move |reply| {n += 1;})
220	    ///     .await
221	    ///     .unwrap();
222	    /// # }
223	    /// ```
224	    #[inline]
225	    pub fn callback_mut<F>(self, callback: F) -> SessionGetBuilder<'a, 'b, Callback<Reply>>
226	    where
227	        F: FnMut(Reply) + Send + Sync + 'static,
228	    {
229	        self.callback(locked(callback))
230	    }
231	
232	    /// Receive the replies for this query with a [`Handler`](crate::handlers::IntoHandler).
233	    ///
234	    /// # Examples
235	    /// ```
236	    /// # #[tokio::main]
237	    /// # async fn main() {
238	    ///
239	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
240	    /// let replies = session
241	    ///     .get("key/expression")
242	    ///     .with(flume::bounded(32))
243	    ///     .await
244	    ///     .unwrap();
245	    /// while let Ok(reply) = replies.recv_async().await {
246	    ///     println!("Received {:?}", reply.result());
247	    /// }
248	    /// # }
249	    /// ```
250	    #[inline]
251	    pub fn with<Handler>(self, handler: Handler) -> SessionGetBuilder<'a, 'b, Handler>
252	    where
253	        Handler: IntoHandler<Reply>,
254	    {
255	        let SessionGetBuilder {
256	            session,
257	            selector,
258	            target,
259	            consolidation,
260	            qos,
261	            destination,
262	            timeout,
263	            value,
264	            attachment,
265	            #[cfg(feature = "unstable")]
266	            source_info,
267	            handler: _,
268	            #[cfg(feature = "unstable")]
269	            cancellation_token,
270	        } = self;
271	        SessionGetBuilder {
272	            session,
273	            selector,
274	            target,
275	            consolidation,
276	            qos,
277	            destination,
278	            timeout,
279	            value,
280	            attachment,
281	            #[cfg(feature = "unstable")]
282	            source_info,
283	            handler,
284	            #[cfg(feature = "unstable")]
285	            cancellation_token,
286	        }
287	    }
288	}
289	impl<Handler> SessionGetBuilder<'_, '_, Handler> {
290	    #[inline]
291	    pub fn payload<IntoZBytes>(mut self, payload: IntoZBytes) -> Self
292	    where
293	        IntoZBytes: Into<ZBytes>,
294	    {
295	        let mut value = self.value.unwrap_or_default();
296	        value.0 = payload.into();
297	        self.value = Some(value);
298	        self
299	    }
300	
301	    /// Change the target(s) of the query.
302	    ///
303	    /// This method allows to specify whether the request should just return the
304	    /// data available in the network which matches the key expression
305	    /// ([QueryTarget::BestMatching], default) or if it should arrive to
306	    /// all queryables matching the key expression ([QueryTarget::All],
307	    /// [QueryTarget::AllComplete]).
308	    ///
309	    /// See also the [`complete`](crate::query::QueryableBuilder::complete) setting
310	    /// of the [`Queryable`](crate::query::Queryable)
311	    #[inline]
312	    pub fn target(self, target: QueryTarget) -> Self {
313	        Self { target, ..self }
314	    }
315	
316	    /// Change the consolidation mode of the query.
317	    ///
318	    /// The multiple replies to a query may arrive from the network. The
319	    /// [`ConsolidationMode`](crate::query::ConsolidationMode) enum defines
320	    /// the strategies of filtering and reordering these replies.
321	    /// The wrapper struct [`QueryConsolidation`](crate::query::QueryConsolidation)
322	    /// allows to set an [`ConsolidationMode::AUTO`](crate::query::QueryConsolidation::AUTO)
323	    /// mode, which lets the implementation choose the best strategy.
324	    #[inline]
325	    pub fn consolidation<QC: Into<QueryConsolidation>>(self, consolidation: QC) -> Self {
326	        Self {
327	            consolidation: consolidation.into(),
328	            ..self
329	        }
330	    }
331	
332	    /// Restrict the matching queryables that will receive the query to the ones that have the given [`Locality`](Locality).
333	    #[inline]
334	    pub fn allowed_destination(self, destination: Locality) -> Self {
335	        Self {
336	            destination,
337	            ..self
338	        }
339	    }
340	
341	    /// Set the query timeout.
342	    #[inline]
